import{_ as a,o as i,c as e,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相逆变器 RMS 估算与欠压保护","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相逆变器 RMS 估算与欠压保护","tags":["power-electronics"],"status":"learning","summary":"均方根（root mean square / RMS）是交流电压有效值的常用表示。对正弦电压，峰值约等于 RMS 值乘以 `sqrt(2)`。欠压保护（undervoltage protection / UV protection）不是看某一个瞬时采样点是否很低，而是常常先估算一段窗口内的 RMS，再配合保持时间判断是"},"headers":[],"relativePath":"content/power/concepts/embedded/single-phase-inverter-rms-protection.md","filePath":"content/power/concepts/embedded/single-phase-inverter-rms-protection.md","lastUpdated":null}'),n={name:"content/power/concepts/embedded/single-phase-inverter-rms-protection.md"};function l(p,s,o,r,h,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="概念-单相逆变器-rms-估算与欠压保护" tabindex="-1">概念：单相逆变器 RMS 估算与欠压保护 <a class="header-anchor" href="#概念-单相逆变器-rms-估算与欠压保护" aria-label="Permalink to &quot;概念：单相逆变器 RMS 估算与欠压保护&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>均方根（root mean square / RMS）是交流电压有效值的常用表示。对正弦电压，峰值约等于 RMS 值乘以 <code>sqrt(2)</code>。欠压保护（undervoltage protection / UV protection）不是看某一个瞬时采样点是否很低，而是常常先估算一段窗口内的 RMS，再配合保持时间判断是否故障。</p><p>本节中文主讲，只讲一个概念：不间断电源（uninterruptible power supply / UPS）固件不能拿瞬时正弦采样点直接判断输出欠压，必须理解 RMS 窗口和保护保持时间。</p><p>本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>单相全桥逆变器（single-phase full-bridge inverter）输出的是交流正弦电压。正弦波每半周都会过零，如果只看瞬时值，那么正常过零也会被误判为欠压。UPS 需要判断“有效输出能力是否低于要求”，所以要用 RMS 或类似的幅值估计。</p><p>保护逻辑还不能一过阈值就跳闸。采样噪声、负载瞬态和窗口边界都会造成短暂误判，因此固件通常会加保持时间、计数器或故障锁存（fault latch）。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>RMS 像是在问：“这一小段时间里，这个交流电压整体有多强？”窗口越长，越平滑，但反应越慢；窗口越短，反应越快，但更容易受相位和噪声影响。保持时间则像二次确认：只有 RMS 连续低于阈值一段时间，才认为是真的欠压。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>滑动窗口 RMS：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>V_rms[k] = sqrt(mean(v[n]^2))   n in recent window</span></span></code></pre></div><p>欠压保持计时：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if V_rms &lt; V_uv_threshold:</span></span>
<span class="line"><span>    timer += Ts</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    timer = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if timer &gt;= hold_time:</span></span>
<span class="line"><span>    fault_latch = true</span></span></code></pre></div><p>其中 <code>Ts</code> 是模数转换器（analog-to-digital converter / ADC）采样周期。</p><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_rms_protection.py</span></span></code></pre></div><p>观察顺序：</p><ul><li><code>v_out</code> 在 80 ms 到 140 ms 之间发生电压跌落。</li><li><code>V_rms</code> 不会在跌落瞬间立刻降到 160 Vrms，而是经过一个窗口逐渐下降。</li><li><code>Hold timer</code> 只有在 <code>V_rms</code> 低于阈值后才开始累计。</li><li><code>Trip latched</code> 一旦拉高，即使电压恢复也保持故障锁存。</li></ul><p>脚本默认保存并自动打开图片；如果无法自动打开，会打印完整图片路径。</p><p>一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_rms_protection.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">undervoltage</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hold</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.005</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_rms_hold_5ms.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_rms_protection.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">undervoltage</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hold</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.030</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_rms_hold_30ms.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>对比 5 ms 和 30 ms 保持时间下的 <code>Hold timer</code> 与 <code>Trip latched</code>。文件名和图内参数框都说明当前保持时间。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>典型固件链路：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADC sample Vout</span></span>
<span class="line"><span>  -&gt; scaling and offset calibration</span></span>
<span class="line"><span>  -&gt; square and sliding-window accumulation</span></span>
<span class="line"><span>  -&gt; RMS estimate</span></span>
<span class="line"><span>  -&gt; threshold compare</span></span>
<span class="line"><span>  -&gt; hold timer / debounce counter</span></span>
<span class="line"><span>  -&gt; fault latch and state-machine action</span></span></code></pre></div><p>工程实现还要处理 ADC 偏置、采样同步、定点数溢出、窗口长度、故障清除条件和状态机优先级。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：瞬时电压低于阈值就是欠压。<br> 正确理解：正弦波正常过零时瞬时电压也接近 0，欠压通常看 RMS 或幅值估计。</li><li>错误理解：RMS 窗口越长越好。<br> 正确理解：窗口越长越稳，但故障发现越慢。</li><li>错误理解：电压恢复后故障应该自动消失。<br> 正确理解：很多 UPS 保护会故障锁存，需要状态机判断是否允许清除。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 RMS 为什么比瞬时电压更适合判断交流输出幅值。</li><li>能说出 RMS 窗口长度和保护响应速度之间的取舍。</li><li>能在图中指出 <code>v_out</code>、<code>V_rms</code>、欠压阈值、保持时间和故障锁存。</li><li>能解释为什么首次跳闸时间晚于首次越阈值时间。</li><li>能基于仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么正弦波正常过零不能被当作欠压故障？</li><li>如果 RMS 窗口从 1 周期改成 0.5 周期，响应速度和误判风险会怎么变化？</li><li>为什么电压恢复后 <code>Trip latched</code> 仍然保持为 1？这和状态机有什么关系？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_inverter_rms_protection.py</code> 看到 RMS 估算在电压跌落后约一个窗口才明显下降。公司平台输出欠压保护使用半周、一周还是多周 RMS 窗口？</li><li>仿真里 <code>UV threshold=180 Vrms</code> 且 <code>hold=15 ms</code> 后才跳闸。真实固件中欠压保持时间通常用计数器、定时器还是状态机周期累计？</li><li>图中电压恢复后 <code>Trip latched</code> 仍保持为 1。公司代码里输出欠压故障需要人工清除、自动恢复，还是满足某些模式条件才清除？</li></ul>`,37)])])}const u=a(n,[["render",l]]);export{k as __pageData,u as default};
